/* eslint-disable react-refresh/only-export-components */
/**
 * MatchHighlightModal — SPEC-F1.1
 *
 * Overlay rapido (3s auto-dismiss) que destaca eventos críticos
 * (gol, vermelho) durante partida live. Pausa ticker via prop.
 */

import { useEffect, useCallback } from 'react';
import { useFocusTrap } from '../hooks/useFocusTrap';
import { CheckCircle, Warning, SoccerBall } from '@phosphor-icons/react';
import '../styles/match-highlight-modal.css';

// ─── pure helpers exportados pra teste ───

export function getHighlightIcon(eventType) {
    if (eventType === 'goal') return SoccerBall;
    if (eventType === 'red' || eventType === 'red-card') return Warning;
    return CheckCircle;
}

export function getHighlightColor(eventType) {
    if (eventType === 'goal') return 'var(--accent)';
    if (eventType === 'red' || eventType === 'red-card') return 'var(--danger)';
    return 'var(--text-main)';
}

export function extractHighlightContext(narrationEntry) {
    if (!narrationEntry) return null;
    const text = narrationEntry.text || '';
    let type = 'other';
    if (text.includes('⚽') || text.toLowerCase().includes('goool')) type = 'goal';
    else if (text.includes('🟥') || text.toLowerCase().includes('vermelho')) type = 'red';
    else return null; // não é highlight
    return {
        type,
        minute: narrationEntry.minute || 0,
        text,
    };
}

export function MatchHighlightModal({ context, onDismiss, autoDismissMs = 3000 }) {
    const trapRef = useFocusTrap(!!context);

    const handleDismiss = useCallback(() => {
        if (typeof onDismiss === 'function') onDismiss();
    }, [onDismiss]);

    useEffect(() => {
        if (!context) return;
        const t = setTimeout(handleDismiss, autoDismissMs);
        const onKey = (e) => { if (e.key === 'Escape') handleDismiss(); };
        window.addEventListener('keydown', onKey);
        return () => {
            clearTimeout(t);
            window.removeEventListener('keydown', onKey);
        };
    }, [context, handleDismiss, autoDismissMs]);

    if (!context) return null;

    const Icon = getHighlightIcon(context.type);
    const color = getHighlightColor(context.type);

    return (
        <div
            ref={trapRef}
            className="ef-highlight-overlay"
            role="alert"
            aria-live="assertive"
        >
            <div className="ef-highlight-card" style={ { '--highlight-color': color }}>
                <div className="ef-highlight-icon-row">
                    <Icon size={64} color={color} weight="fill" />
                </div>
                <div className="ef-highlight-minute">
                    MINUTO {context.minute}
                </div>
                <div className="ef-highlight-text">
                    {context.text}
                </div>
            </div>
        </div>
    );
}

export default MatchHighlightModal;

import './MatchHighlightVideo.css';

import { useState, useEffect } from 'react';
/**
 * MatchHighlightVideo
 * An interactive 2D cinematic viewer that translates match events into 
 * beautiful 16-bit full frame sequences, inspired by ISSSD.
 * 
 * @param {Object} props
 * @param {Object} props.event - The current match event object from narration
 * @param {boolean} props.isHomeAttacking - Determines placement/team
 */
export default function MatchHighlightVideo({ event, isHomeAttacking = true }) {
    const [animState, setAnimState] = useState({
        imageSrc: null,
        isGoal: false,
        flash: false,
        showBanner: true
    });

    useEffect(() => {
        if (!event) return;

        const text = (event.text || '').toLowerCase();
        let imgSrc = null;
        let isGoal = false;

        // Cinematic Event Mapping based on text
        if (text.includes('gol') || text.includes('golaço')) {
            isGoal = true;
            // Depending on who attacks, show the respective celebration
            imgSrc = isHomeAttacking ? '/assets/sprites/isssd_red_goal.png' : '/assets/sprites/isssd_blue_goal.png';
        } else if (text.includes('falta') || text.includes('cartão') || text.includes('lesão')) {
            imgSrc = '/assets/sprites/isssd_foul.png';
        } else if (text.includes('juiz') || text.includes('árbitro') || text.includes('apita')) {
            imgSrc = '/assets/sprites/isssd_dog_referee.png';
        } else if (text.includes('chute') || text.includes('defesa') || text.includes('espalma') || text.includes('perigo')) {
            // General action scenes could just reuse the foul scene or a generic stadium scene. 
            // For now, let's show the referee dog looking concerned or just a tackle.
            imgSrc = '/assets/sprites/isssd_foul.png'; 
        }

        if (imgSrc) {
            setAnimState({
                imageSrc: imgSrc,
                isGoal,
                flash: isGoal,
                showBanner: true
            });

            // Clear flash after animation
            if (isGoal) {
                setTimeout(() => {
                    setAnimState(prev => ({ ...prev, flash: false }));
                }, 500);
            }
        } else {
            // If it's a generic pass, hide it.
            setAnimState(prev => ({ ...prev, imageSrc: null }));
        }

    }, [event, isHomeAttacking]);

    if (!event || !animState.imageSrc) return null;

    return (
        <div className={`ef-match-highlight-video ${animState.flash ? 'ef-match-highlight-video--flash' : ''}`}>
            {/* Full-screen cinematic pixel art background */}
            <img 
                src={animState.imageSrc} 
                alt="Highlight" 
                className="ef-match-highlight-video__cinematic-bg"
            />

            <div className="ef-match-highlight-video__overlay"></div>

            {animState.showBanner && (
                <div className="ef-match-highlight-video__banner">
                    {event.minute}' - {event.text}
                </div>
            )}

            {animState.isGoal && (
                <div className="ef-match-highlight-video__goal-text">GOL!</div>
            )}
        </div>
    );
}

/* eslint-disable react-refresh/only-export-components */
/**
 * MidMatchCardModal — SPEC-B2.2
 *
 * Overlay pausa-style com carta de decisão mid-match.
 * Pronto para wiring no MatchView quando shouldTriggerMidMatch dispara.
 */

import { useCallback, useEffect } from 'react';
import { ChatCircle, X } from '@phosphor-icons/react';
import '../styles/decision-modal.css';

// ─── helpers exportados para teste ───

export function formatEffectChip(effect) {
    if (!effect || typeof effect !== 'object') return '';
    const parts = [];
    if (typeof effect.moralDelta === 'number') {
        parts.push(`Moral ${effect.moralDelta > 0 ? '+' : ''}${effect.moralDelta}`);
    }
    if (typeof effect.energyDelta === 'number') {
        parts.push(`Energia ${effect.energyDelta > 0 ? '+' : ''}${effect.energyDelta}`);
    }
    if (typeof effect.tacticShift === 'string' && effect.tacticShift.length > 0) {
        parts.push(`Tática: ${effect.tacticShift}`);
    }
    return parts.join(' · ');
}

export function MidMatchCardModal({ card, onChoose, onClose }) {
    const handleChoose = useCallback((opt, idx) => {
        if (typeof onChoose === 'function') onChoose(opt, idx);
        if (typeof onClose === 'function') onClose();
    }, [onChoose, onClose]);

    const handleClose = useCallback(() => {
        if (typeof onClose === 'function') onClose();
    }, [onClose]);

    useEffect(() => {
        if (!card) return;
        const onKey = (e) => {
            if (e.key === 'Escape') handleClose();
        };
        window.addEventListener('keydown', onKey);
        return () => window.removeEventListener('keydown', onKey);
    }, [card, handleClose]);

    if (!card) return null;

    return (
        <div
            className="ef-decision-overlay"
            role="dialog"
            aria-modal="true"
            aria-labelledby="ef-midmatch-title"
        >
            <div className="ef-decision-card" style={ { '--decision-accent': 'var(--accent)' }}>
                <button
                    type="button"
                    onClick={handleClose}
                    aria-label="Fechar carta"
                    className="ef-decision-close"
                >
                    <X size={14} weight="bold" />
                </button>

                <div className="ef-decision-header">
                    <ChatCircle size={20} color="var(--accent)" weight="fill" />
                    <span id="ef-midmatch-title" className="ef-decision-title">
                        DECISÃO DO TÉCNICO
                    </span>
                </div>

                <p className="ef-decision-body">
                    {card.text}
                </p>

                <div className="ef-decision-options">
                    {card.options.map((opt, idx) => {
                        const chip = formatEffectChip(opt.effect);
                        return (
                            <button
                                key={`${card.id}-opt-${idx}`}
                                type="button"
                                onClick={() => handleChoose(opt, idx)}
                                className="ef-decision-option-btn"
                            >
                                <div className={`ef-decision-option-label${chip ? ' ef-decision-option-label--has-chip' : ''}`}>{opt.label}</div>
                                {chip && (
                                    <div className="ef-decision-option-chip">
                                        {chip}
                                    </div>
                                )}
                            </button>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

export default MidMatchCardModal;

