                titles: legacy.titles || [],
                seasons: (legacy.seasons || []).slice(-10),
                topScorers,
                insights: stats.insights || {},
                identity,
            });
        }, 1000);
        return () => clearInterval(id);
    }, [controllerRef]);

    if (!snapshot || !snapshot.team) return null;

